from __future__ import annotations

import logging
from typing import Optional, Any, BinaryIO, Iterable, Union

import laspy
import numpy as np
import pyproj
from laspy.copc import CopcInfoVlr
from pyproj.exceptions import CRSError
from typing_extensions import Self

from geosat.cloud.io.las.private_namespace_converters import (
    private_metadata_to_vlrs,
    vlrs_to_private_metadata,
)
from geosat.cloud.metadata.base_namespace import Metadata
from geosat.cloud.metadata.private_namespace import PrivateNamespace
from geosat.cloud.pointcloud import PointCloud, Reader, Writer

UINT8_MAX = np.iinfo(np.uint8).max


class LasReader(Reader):
    """A :class:`.Reader` to read a :class:`PointCloud` from a binary stream in the
    LAS/LAZ format: https://www.asprs.org/wp-content/uploads/2019/03/LAS_1_4_r14.pdf

    :param file_object: A stream containing a binary representation of a LAS/LAZ
        point cloud
    :param fields_to_read: Indicate the fields of the point cloud that should be
        loaded from the given point cloud. If "all" is provided, all the fields will
        be read.
    :param closefd: Indicate if the given ``file_object`` must be closed when this
        :class:`Reader` is closed.
    """

    def __init__(
        self,
        file_object: BinaryIO,
        fields_to_read: Union[str, Iterable[str]] = "all",
        closefd: bool = True,
    ) -> None:
        self.las_reader = laspy.open(file_object, closefd=closefd)
        self.fields_to_read = fields_to_read

    @classmethod
    def from_source(cls, source: BinaryIO) -> Self:
        return cls(source)

    def header(self) -> Any:
        return self.las_reader.header

    def read(self, n: int = -1) -> PointCloud:
        point_record = self.las_reader.read_points(n)

        coords = np.vstack((point_record.x, point_record.y, point_record.z)).transpose()

        dimensions_names = list(point_record.point_format.dimension_names)[3:]
        if self.fields_to_read != "all":
            dimensions_names = [
                name for name in dimensions_names if name in self.fields_to_read
            ]

        # We copy so that fields are contiguous arrays
        fields = {dim: np.array(point_record[dim]) for dim in dimensions_names}

        def shift_to_8_bits_if_needed(field: np.ndarray) -> None:
            if len(field) == 0:
                return

            if field.max() > UINT8_MAX:
                field >>= 8

        try:
            shift_to_8_bits_if_needed(fields["red"])
            shift_to_8_bits_if_needed(fields["green"])
            shift_to_8_bits_if_needed(fields["blue"])
        except KeyError:
            pass

        # Remove the extra bytes vlr otherwise it may be duplicated
        # when we save the las
        try:
            self.las_reader.header.vlrs.extract("ExtraBytesVlr")
        except IndexError:
            pass

        metadata: Metadata = {
            "las": {
                "point_format_id": self.las_reader.header.point_format.id,
                "version": self.las_reader.header.version,
                "vlrs": self.las_reader.header.vlrs,
                "scales": self.las_reader.header.scales,
                "offsets": self.las_reader.header.offsets,
            }
        }
        private_metadata: PrivateNamespace = vlrs_to_private_metadata(
            self.las_reader.header.vlrs
        )
        metadata["geosat"] = private_metadata

        try:
            crs: Optional[pyproj.CRS] = self.las_reader.header.parse_crs()
        except CRSError as exception:
            logging.warning(f"Error while parsing CRS: {exception}")
        else:
            if crs is not None:
                metadata["srs_wkt"] = crs.to_wkt()

        return PointCloud(coords, fields, metadata)

    def close(self) -> None:
        self.las_reader.close()


def _add_new_fields_to_header(header: laspy.LasHeader, point_cloud: PointCloud) -> None:
    las_standard_dims_names = set(header.point_format.standard_dimension_names)
    for field_name, field_value in point_cloud.fields.items():
        if field_name in las_standard_dims_names:
            continue
        if field_value.ndim <= 1:
            dtype = field_value.dtype
        elif field_value.ndim == 2:
            dtype = np.dtype((field_value.dtype, field_value.shape[1]))
        else:
            raise ValueError(
                f"Attempting to save a field '{field_name}' with more than "
                f"two dimensions: shape={field_value.shape}"
            )
        header.add_extra_dim(laspy.ExtraBytesParams(name=field_name, type=dtype))


class LasWriter(Writer):
    """A :class:`.Writer` to write a :class:`PointCloud` to a binary stream in the
    LAS/LAZ format: https://www.asprs.org/wp-content/uploads/2019/03/LAS_1_4_r14.pdf

    :param dest: A stream where the :class:`PointCloud` should be written
    :param closefd: Indicate if the given ``dest`` must be closed when this
        :class:`Writer` is closed.
    """

    _do_compress = False

    def __init__(self, dest: BinaryIO, closefd: bool = True) -> None:
        self.las_writer: Optional[laspy.LasWriter] = None
        self.dest = dest
        self.closefd = closefd

    @classmethod
    def from_dest(cls, dest: BinaryIO) -> Self:
        return cls(dest)

    def write(self, point_cloud: PointCloud) -> None:
        if self.las_writer is None:
            self.las_writer = self._init_writer(point_cloud)

        point_record = laspy.ScaleAwarePointRecord.zeros(
            len(point_cloud), header=self.las_writer.header
        )
        point_record.x = point_cloud.x
        point_record.y = point_cloud.y
        point_record.z = point_cloud.z

        def shift_to_16_bits_if_needed(field: np.ndarray) -> np.ndarray:
            if len(field) and field.max() <= UINT8_MAX:
                return field << 8
            else:
                return field

        for field_name, field_values in point_cloud.fields.items():
            if field_name in ("red", "green", "blue"):
                field_values = shift_to_16_bits_if_needed(field_values)
            point_record[field_name] = field_values

        self.las_writer.write_points(point_record)

    def close(self) -> None:
        if self.las_writer is not None:
            self.las_writer.close()

    def _init_writer(self, point_cloud: PointCloud) -> laspy.LasWriter:
        try:
            point_format_id = point_cloud.metadata["las"]["point_format_id"]
            version = point_cloud.metadata["las"]["version"]
            vlrs = point_cloud.metadata["las"]["vlrs"]
            scales = point_cloud.metadata["las"]["scales"]
            offsets = point_cloud.metadata["las"]["offsets"]
        except KeyError:
            point_format_id, version = 3, "1.2"
            scales = [0.001, 0.001, 0.001]
            offsets = point_cloud.bb_min() if len(point_cloud) else np.zeros(3)
            vlrs = []

        private_metadata = point_cloud.metadata["geosat"]
        private_vlrs = private_metadata_to_vlrs(private_metadata)
        vlrs.extend(private_vlrs)

        header = laspy.LasHeader(point_format=point_format_id, version=version)
        header.scales = scales
        header.offsets = offsets
        # Filter out the CopcInfoVlr, as it is not supported for writing by laspy <= 2.5.2:
        header.vlrs = [vlr for vlr in vlrs if not isinstance(vlr, CopcInfoVlr)]
        _add_new_fields_to_header(header, point_cloud)

        return laspy.LasWriter(
            self.dest, header, do_compress=self._do_compress, closefd=self.closefd
        )


class LazReader(LasReader):
    """A LasReader for compressed point clouds"""


class LazWriter(LasWriter):
    """A LasWriter that systematically compresses
    the :class:`.PointCloud` instances it writes"""

    _do_compress = True
